#include <stdio.h>

int longest_subset_zero_sum(int arr[], int n) {
    int max_len = 0;

    for (int i = 0; i < n; i++) {
        int sum = 0;
        for (int j = i; j < n; j++) {
            sum += arr[j];
            if (sum == 0) {
                int len = j - i + 1;
                if (len > max_len)
                    max_len = len;
            }
        }
    }

    return max_len;
}

